import React, { useState, useEffect, useContext } from 'react';
import { useParams, Link } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import LoadingSpinner from '../components/common/LoadingSpinner';
import MovieCard from '../components/movies/MovieCard';
import { getMovieDetails } from '../services/movieService';
import { rateMovie, checkUserRating } from '../services/ratingService';
import { getSimilarMovies } from '../services/recommendationService';
import '../styles/MovieDetailsPage.css';

const MovieDetailsPage = () => {
  const { movieId } = useParams();
  const { user, isAuthenticated } = useContext(AuthContext);
  const [movie, setMovie] = useState(null);
  const [similarMovies, setSimilarMovies] = useState([]);
  const [userRating, setUserRating] = useState(null);
  const [newRating, setNewRating] = useState(0);
  const [review, setReview] = useState('');
  const [hoverRating, setHoverRating] = useState(0);
  const [loading, setLoading] = useState(true);
  const [ratingLoading, setRatingLoading] = useState(false);
  const [error, setError] = useState(null);
  const [showRatingForm, setShowRatingForm] = useState(false);

  // ADD DEBUGGING - Change 1
  console.log('🎬 MovieDetailsPage render:', {
    movieId,
    movie: movie ? { id: movie.id, title: movie.title } : null,
    loading,
    error,
    isAuthenticated,
    user
  });

  useEffect(() => {
    if (movieId) {
      console.log('🎬 useEffect: movieId changed to:', movieId);
      fetchMovieData();
    } else {
      console.error('❌ No movieId provided');
      setError('No movie ID provided');
      setLoading(false);
    }
  }, [movieId]);

  useEffect(() => {
    if (isAuthenticated && movieId) {
      console.log('🎬 useEffect: fetching user rating for movie:', movieId);
      fetchUserRating();
    }
  }, [isAuthenticated, movieId]);

  // IMPROVED fetchMovieData function - Change 2
  const fetchMovieData = async () => {
    if (!movieId) {
      console.error('❌ fetchMovieData: No movieId');
      setError('No movie ID provided');
      setLoading(false);
      return;
    }

    console.log('🚀 fetchMovieData: Starting for movieId:', movieId);
    setLoading(true);
    setError(null);

    try {
      // First, try to get movie details
      console.log('📞 Calling getMovieDetails...');
      const movieData = await getMovieDetails(movieId);
      console.log('📊 Movie details response:', movieData);

      if (!movieData) {
        throw new Error('No movie data returned from API');
      }

      // Check if movieData has the expected structure
      if (!movieData.id && !movieData.title) {
        console.error('❌ Invalid movie data structure:', movieData);
        throw new Error('Invalid movie data received');
      }

      setMovie(movieData);
      console.log('✅ Movie details set successfully');

      // Then try to get similar movies (don't fail the whole page if this fails)
      try {
        console.log('📞 Calling getSimilarMovies...');
        const similarData = await getSimilarMovies(movieId, 8);
        console.log('📊 Similar movies response:', similarData);

        if (similarData && similarData.similar_movies) {
          setSimilarMovies(similarData.similar_movies);
          console.log('✅ Similar movies set:', similarData.similar_movies.length);
        } else if (Array.isArray(similarData)) {
          setSimilarMovies(similarData);
          console.log('✅ Similar movies set (array format):', similarData.length);
        } else {
          console.warn('⚠️ No similar movies found');
          setSimilarMovies([]);
        }
      } catch (similarError) {
        console.warn('⚠️ Failed to fetch similar movies (non-critical):', similarError);
        setSimilarMovies([]);
      }

    } catch (error) {
      console.error('💥 Error in fetchMovieData:', error);
      console.error('💥 Error details:', {
        message: error.message,
        response: error.response?.data,
        status: error.response?.status,
        stack: error.stack
      });

      let errorMessage = 'Failed to load movie details. Please try again.';

      if (error.response?.status === 404) {
        errorMessage = 'Movie not found. It may have been removed or the link is incorrect.';
      } else if (error.response?.status === 403) {
        errorMessage = 'Access denied. You may need to log in to view this movie.';
      } else if (error.response?.status >= 500) {
        errorMessage = 'Server error. Please try again later.';
      } else if (!navigator.onLine) {
        errorMessage = 'No internet connection. Please check your connection and try again.';
      }

      setError(errorMessage);
    } finally {
      console.log('✅ fetchMovieData completed, setting loading to false');
      setLoading(false);
    }
  };

  // IMPROVED fetchUserRating function - Change 3
  const fetchUserRating = async () => {
    if (!movieId || !isAuthenticated) return;

    try {
      console.log('📞 Fetching user rating for movie:', movieId);
      const ratingData = await checkUserRating(movieId);
      console.log('📊 User rating response:', ratingData);

      if (ratingData && ratingData.has_rated && ratingData.rating) {
        setUserRating(ratingData.rating);
        setNewRating(ratingData.rating.rating);
        setReview(ratingData.rating.review || '');
        console.log('✅ User rating set:', ratingData.rating);
      } else {
        console.log('ℹ️ User has not rated this movie');
        setUserRating(null);
        setNewRating(0);
        setReview('');
      }
    } catch (error) {
      console.warn('⚠️ Error fetching user rating (non-critical):', error);
      // Don't set error state for rating fetch failures
    }
  };

  const handleRatingSubmit = async (e) => {
    e.preventDefault();
    if (!newRating || newRating < 1 || newRating > 5) {
      alert('Please select a rating between 1 and 5 stars');
      return;
    }

    setRatingLoading(true);

    try {
      const ratingData = await rateMovie({
        movie_id: movieId,
        rating: newRating,
        review: review.trim()
      });

      setUserRating(ratingData.rating);
      setShowRatingForm(false);

      // Refresh movie data to get updated rating
      fetchMovieData();

      alert('Rating saved successfully!');
    } catch (error) {
      console.error('Error saving rating:', error);
      alert('Failed to save rating. Please try again.');
    } finally {
      setRatingLoading(false);
    }
  };

  const renderStars = (rating, interactive = false, size = 'medium') => {
    const stars = [];
    const maxStars = 5;

    for (let i = 1; i <= maxStars; i++) {
      const filled = i <= (interactive ? (hoverRating || newRating) : rating);
      stars.push(
        <span
          key={i}
          className={`star ${size} ${filled ? 'filled' : 'empty'} ${interactive ? 'interactive' : ''}`}
          onClick={interactive ? () => setNewRating(i) : undefined}
          onMouseEnter={interactive ? () => setHoverRating(i) : undefined}
          onMouseLeave={interactive ? () => setHoverRating(0) : undefined}
        >
          {filled ? '★' : '☆'}
        </span>
      );
    }

    return <span className="stars-container">{stars}</span>;
  };

  const formatDate = (dateString) => {
    if (!dateString) return '';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };

  // IMPROVED LOADING STATE - Change 4
  if (loading) {
    console.log('🔄 Showing loading spinner');
    return <LoadingSpinner />;
  }

  // IMPROVED ERROR HANDLING - Change 5
  if (error) {
    console.log('❌ Showing error state:', error);
    return (
      <div className="error-container">
        <h2>Oops! Something went wrong</h2>
        <p>{error}</p>
        <div className="error-actions">
          <button 
            onClick={() => {
              console.log('🔄 Retrying movie data fetch');
              fetchMovieData();
            }}
            className="retry-button"
          >
            🔄 Try Again
          </button>
          <Link to="/movies" className="back-button">
            ← Browse Movies
          </Link>
        </div>
        {/* Debug info in development */}
        {process.env.NODE_ENV === 'development' && (
          <div className="debug-info" style={{ 
            marginTop: '20px', 
            padding: '10px', 
            background: '#f5f5f5', 
            fontSize: '12px',
            fontFamily: 'monospace'
          }}>
            <details>
              <summary>Debug Info (Development Only)</summary>
              <p><strong>Movie ID:</strong> {movieId}</p>
              <p><strong>Error:</strong> {error}</p>
              <p><strong>Auth Status:</strong> {isAuthenticated ? 'Authenticated' : 'Not authenticated'}</p>
              <p><strong>User:</strong> {user?.username || 'None'}</p>
            </details>
          </div>
        )}
      </div>
    );
  }

  // CHECK IF MOVIE EXISTS - Change 6
  if (!movie) {
    console.log('❌ No movie data available');
    return (
      <div className="error-container">
        <h2>Movie not found</h2>
        <p>The movie you're looking for doesn't exist or couldn't be loaded.</p>
        <div className="error-actions">
          <button 
            onClick={() => {
              console.log('🔄 Retrying movie data fetch');
              fetchMovieData();
            }}
            className="retry-button"
          >
            🔄 Try Again
          </button>
          <Link to="/movies" className="back-button">
            ← Browse Movies
          </Link>
        </div>
      </div>
    );
  }

  console.log('✅ Rendering movie details for:', movie.title);

  return (
    <div className="movie-details-page">
      {/* Hero Section */}
      <div className="movie-hero">
        <div className="movie-backdrop">
          <img
            src={movie.poster_url || '/placeholder-movie.jpg'}
            alt={movie.title}
            className="backdrop-image"
            onError={(e) => {
              console.warn('⚠️ Backdrop image failed to load');
              e.target.src = '/placeholder-movie.jpg';
            }}
          />
          <div className="backdrop-overlay"></div>
        </div>

        <div className="movie-hero-content">
          <div className="movie-poster">
            <img
              src={movie.poster_url || '/placeholder-movie.jpg'}
              alt={movie.title}
              onError={(e) => {
                console.warn('⚠️ Poster image failed to load');
                e.target.src = '/placeholder-movie.jpg';
              }}
            />
          </div>

          <div className="movie-info">
            <h1 className="movie-title">{movie.title}</h1>
            <div className="movie-meta">
              {movie.year && <span className="movie-year">{movie.year}</span>}
              <div className="movie-rating">
                {movie.avg_rating && renderStars(movie.avg_rating)}
                <span className="rating-text">
                  {movie.avg_rating ? 
                    `${movie.avg_rating.toFixed(1)} (${movie.rating_count || 0} ratings)` :
                    'No ratings yet'
                  }
                </span>
              </div>
            </div>

            {movie.genres && movie.genres.length > 0 && (
              <div className="movie-genres">
                {movie.genres.map(genre => (
                  <Link
                    key={genre}
                    to={`/movies?genre=${encodeURIComponent(genre)}`}
                    className="genre-tag"
                  >
                    {genre}
                  </Link>
                ))}
              </div>
            )}

            {movie.plot && <p className="movie-plot">{movie.plot}</p>}

            {/* User Rating Section */}
            {isAuthenticated && (
              <div className="user-rating-section">
                {userRating ? (
                  <div className="existing-rating">
                    <h4>Your Rating:</h4>
                    <div className="rating-display">
                      {renderStars(userRating.rating)}
                      <span>({userRating.rating}/5)</span>
                      <button
                        onClick={() => setShowRatingForm(true)}
                        className="edit-rating-button"
                      >
                        Edit
                      </button>
                    </div>
                    {userRating.review && (
                      <p className="user-review">"{userRating.review}"</p>
                    )}
                  </div>
                ) : (
                  <button
                    onClick={() => setShowRatingForm(true)}
                    className="rate-movie-button"
                  >
                    ⭐ Rate this Movie
                  </button>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Rating Form Modal */}
      {showRatingForm && (
        <div className="rating-modal-overlay" onClick={() => setShowRatingForm(false)}>
          <div className="rating-modal" onClick={(e) => e.stopPropagation()}>
            <form onSubmit={handleRatingSubmit}>
              <h3>{userRating ? 'Update Your Rating' : 'Rate This Movie'}</h3>

              <div className="rating-input">
                <label>Your Rating:</label>
                <div className="stars-input">
                  {renderStars(newRating, true, 'large')}
                </div>
                <span className="rating-value">
                  {newRating > 0 ? `${newRating}/5 stars` : 'Select a rating'}
                </span>
              </div>

              <div className="review-input">
                <label htmlFor="review">Review (optional):</label>
                <textarea
                  id="review"
                  value={review}
                  onChange={(e) => setReview(e.target.value)}
                  placeholder="Share your thoughts about this movie..."
                  rows="4"
                  maxLength="1000"
                />
                <span className="char-count">{review.length}/1000</span>
              </div>

              <div className="modal-buttons">
                <button
                  type="button"
                  onClick={() => setShowRatingForm(false)}
                  className="cancel-button"
                  disabled={ratingLoading}
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="submit-rating-button"
                  disabled={ratingLoading || newRating === 0}
                >
                  {ratingLoading ? 'Saving...' : 'Save Rating'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Reviews Section */}
      {movie.reviews && movie.reviews.length > 0 && (
        <section className="reviews-section">
          <h2>Recent Reviews</h2>
          <div className="reviews-list">
            {movie.reviews.slice(0, 5).map((review, index) => (
              <div key={index} className="review-item">
                <div className="review-header">
                  <span className="reviewer-name">{review.username}</span>
                  <div className="review-rating">
                    {renderStars(review.rating, false, 'small')}
                  </div>
                  <span className="review-date">
                    {formatDate(review.timestamp)}
                  </span>
                </div>
                {review.review && (
                  <p className="review-text">"{review.review}"</p>
                )}
              </div>
            ))}
          </div>
        </section>
      )}

      {/* Similar Movies Section */}
      {similarMovies.length > 0 && (
        <section className="similar-movies-section">
          <h2>Similar Movies</h2>
          <div className="similar-movies-grid">
            {similarMovies.map(movie => (
              <MovieCard key={movie.id} movie={movie} />
            ))}
          </div>
        </section>
      )}

      {/* Back Navigation */}
      <div className="back-navigation">
        <Link to="/movies" className="back-button">
          ← Back to Movies
        </Link>
      </div>
    </div>
  );
};

export default MovieDetailsPage;
